{
  "name": "@node/diet-tracker",
  "version": "1.0.0",
  "description": "Track daily meals, calories, macros, and weekly intake with bar chart visualization",
  "modnet": {
    "contentType": "health",
    "structure": "list",
    "mechanics": ["track", "chart"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber'

export type MealEntry = {
  id: string
  name: string
  items: FoodItem[]
  timestamp: string
  date: string
}

export type FoodItem = {
  name: string
  calories: number
  categories: FoodCategory[]
}

export type DailySummary = {
  date: string
  totalCalories: number
  meals: MealEntry[]
  categoryBreakdown: Record<FoodCategory, number>
  goal: number
  remaining: number
}

export type WeeklyDay = {
  date: string
  dayLabel: string
  totalCalories: number
}

export type Settings = {
  dailyGoal: number
}

import type { MealEntry, Settings } from './types'

const DATA_DIR = import.meta.dir + '/data'
const MEALS_FILE = `${DATA_DIR}/meals.jsonl`
const SETTINGS_FILE = `${DATA_DIR}/settings.json`

const DEFAULT_SETTINGS: Settings = {
  dailyGoal: 2000,
}

export const readMeals = async (): Promise<MealEntry[]> => {
  const file = Bun.file(MEALS_FILE)
  const exists = await file.exists()
  if (!exists) return []

  const text = await file.text()
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as MealEntry)
}

export const appendMeal = async (meal: MealEntry): Promise<void> => {
  const file = Bun.file(MEALS_FILE)
  const exists = await file.exists()
  const line = JSON.stringify(meal) + '\n'

  if (exists) {
    const existing = await file.text()
    await Bun.write(MEALS_FILE, existing + line)
  } else {
    await Bun.write(MEALS_FILE, line)
  }
}

export const deleteMeal = async (id: string): Promise<boolean> => {
  const meals = await readMeals()
  const filtered = meals.filter((m) => m.id !== id)
  if (filtered.length === meals.length) return false

  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length > 0 ? '\n' : '')
  await Bun.write(MEALS_FILE, content)
  return true
}

export const readSettings = async (): Promise<Settings> => {
  const file = Bun.file(SETTINGS_FILE)
  const exists = await file.exists()
  if (!exists) return { ...DEFAULT_SETTINGS }

  const text = await file.text()
  return JSON.parse(text) as Settings
}

export const writeSettings = async (settings: Settings): Promise<void> => {
  await Bun.write(SETTINGS_FILE, JSON.stringify(settings, null, 2))
}

import type { FoodCategory, FoodItem, MealEntry, DailySummary, WeeklyDay } from './types'
import { readMeals, appendMeal, deleteMeal, readSettings, writeSettings } from './data'

const generateId = (): string => crypto.randomUUID()

const toDateString = (d: Date): string => d.toISOString().split('T')[0]

const todayString = (): string => toDateString(new Date())

export type LogMealInput = {
  name: string
  items?: FoodItem[]
  calories?: number
  categories?: FoodCategory[]
  timestamp?: string
}

export const logMeal = async (input: LogMealInput): Promise<MealEntry> => {
  const now = new Date()
  const timestamp = input.timestamp ?? now.toISOString()
  const date = timestamp.split('T')[0]

  const items: FoodItem[] = input.items ?? [
    {
      name: input.name,
      calories: input.calories ?? 0,
      categories: input.categories ?? [],
    },
  ]

  const meal: MealEntry = {
    id: generateId(),
    name: input.name,
    items,
    timestamp,
    date,
  }

  await appendMeal(meal)
  return meal
}

export const removeMeal = async (id: string): Promise<boolean> => {
  return deleteMeal(id)
}

export const getMealsForDate = async (date?: string): Promise<MealEntry[]> => {
  const targetDate = date ?? todayString()
  const meals = await readMeals()
  return meals.filter((m) => m.date === targetDate)
}

const sumCalories = (meals: MealEntry[]): number =>
  meals.reduce((sum, meal) => sum + meal.items.reduce((s, item) => s + item.calories, 0), 0)

const buildCategoryBreakdown = (meals: MealEntry[]): Record<FoodCategory, number> => {
  const breakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  }

  for (const meal of meals) {
    for (const item of meal.items) {
      for (const cat of item.categories) {
        breakdown[cat] += item.calories
      }
    }
  }

  return breakdown
}

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? todayString()
  const meals = await getMealsForDate(targetDate)
  const totalCalories = sumCalories(meals)
  const settings = await readSettings()

  return {
    date: targetDate,
    totalCalories,
    meals,
    categoryBreakdown: buildCategoryBreakdown(meals),
    goal: settings.dailyGoal,
    remaining: settings.dailyGoal - totalCalories,
  }
}

export const getWeeklySummary = async (endDate?: string): Promise<WeeklyDay[]> => {
  const end = endDate ? new Date(endDate + 'T12:00:00') : new Date()
  const allMeals = await readMeals()
  const days: WeeklyDay[] = []
  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

  for (let i = 6; i >= 0; i--) {
    const d = new Date(end)
    d.setDate(d.getDate() - i)
    const dateStr = toDateString(d)
    const dayMeals = allMeals.filter((m) => m.date === dateStr)

    days.push({
      date: dateStr,
      dayLabel: dayNames[d.getDay()],
      totalCalories: sumCalories(dayMeals),
    })
  }

  return days
}

export const setDailyGoal = async (calories: number): Promise<void> => {
  const settings = await readSettings()
  settings.dailyGoal = calories
  await writeSettings(settings)
}

export const getDailyGoal = async (): Promise<number> => {
  const settings = await readSettings()
  return settings.dailyGoal
}

import { h, Fragment } from 'plaited'
import type { DailySummary, WeeklyDay, FoodCategory } from './types'

const CATEGORY_COLORS: Record<FoodCategory, string> = {
  protein: '#4CAF50',
  carbs: '#FF9800',
  fat: '#F44336',
  fiber: '#8BC34A',
}

const styles = {
  container: {
    fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
    maxWidth: '640px',
    margin: '0 auto',
    padding: '16px',
    color: '#1a1a1a',
  },
  header: {
    fontSize: '24px',
    fontWeight: '700',
    marginBottom: '16px',
  },
  section: {
    marginBottom: '24px',
  },
  sectionTitle: {
    fontSize: '16px',
    fontWeight: '600',
    marginBottom: '8px',
    color: '#555',
    textTransform: 'uppercase' as const,
    letterSpacing: '0.5px',
  },
  goalBar: {
    width: '100%',
    height: '24px',
    backgroundColor: '#e0e0e0',
    borderRadius: '12px',
    overflow: 'hidden',
    position: 'relative' as const,
  },
  goalFill: (pct: number, over: boolean) => ({
    width: `${Math.min(pct, 100)}%`,
    height: '100%',
    backgroundColor: over ? '#F44336' : '#4CAF50',
    borderRadius: '12px',
    transition: 'width 0.3s ease',
  }),
  goalText: {
    fontSize: '14px',
    marginTop: '4px',
    color: '#777',
  },
  mealCard: {
    border: '1px solid #e0e0e0',
    borderRadius: '8px',
    padding: '12px',
    marginBottom: '8px',
  },
  mealName: {
    fontWeight: '600',
    fontSize: '15px',
  },
  mealTime: {
    fontSize: '12px',
    color: '#999',
  },
  mealCalories: {
    fontSize: '14px',
    fontWeight: '500',
    color: '#333',
  },
  tag: (color: string) => ({
    display: 'inline-block',
    padding: '2px 8px',
    borderRadius: '10px',
    fontSize: '11px',
    fontWeight: '500',
    backgroundColor: color + '22',
    color,
    marginRight: '4px',
    marginTop: '4px',
  }),
  chartRow: {
    display: 'flex',
    alignItems: 'center',
    marginBottom: '6px',
    gap: '8px',
  },
  chartLabel: {
    width: '36px',
    fontSize: '13px',
    fontWeight: '500',
    textAlign: 'right' as const,
    flexShrink: '0',
  },
  chartBarContainer: {
    flex: '1',
    height: '28px',
    backgroundColor: '#f0f0f0',
    borderRadius: '4px',
    position: 'relative' as const,
    overflow: 'hidden',
  },
  chartBar: (pct: number, over: boolean) => ({
    width: `${Math.min(pct, 100)}%`,
    height: '100%',
    backgroundColor: over ? '#F44336' : '#2196F3',
    borderRadius: '4px',
  }),
  chartValue: {
    width: '50px',
    fontSize: '12px',
    color: '#666',
    textAlign: 'right' as const,
    flexShrink: '0',
  },
  goalLine: (pct: number) => ({
    position: 'absolute' as const,
    left: `${Math.min(pct, 100)}%`,
    top: '0',
    bottom: '0',
    width: '2px',
    backgroundColor: '#FF5722',
    zIndex: '1',
  }),
  categoryRow: {
    display: 'flex',
    justifyContent: 'space-between',
    padding: '4px 0',
    fontSize: '14px',
  },
}

export const renderDailySummary = (summary: DailySummary) => {
  const pct = summary.goal > 0 ? (summary.totalCalories / summary.goal) * 100 : 0
  const isOver = summary.totalCalories > summary.goal

  return h('div', { style: styles.container },
    h('div', { style: styles.header }, `Diet Tracker — ${summary.date}`),

    h('div', { style: styles.section },
      h('div', { style: styles.sectionTitle }, 'Daily Goal'),
      h('div', { style: styles.goalBar },
        h('div', { style: styles.goalFill(pct, isOver) }),
      ),
      h('div', { style: styles.goalText },
        `${summary.totalCalories} / ${summary.goal} kcal`,
        isOver
          ? ` (${summary.totalCalories - summary.goal} over)`
          : ` (${summary.remaining} remaining)`,
      ),
    ),

    h('div', { style: styles.section },
      h('div', { style: styles.sectionTitle }, 'Category Breakdown'),
      ...(['protein', 'carbs', 'fat', 'fiber'] as FoodCategory[]).map((cat) =>
        h('div', { style: styles.categoryRow },
          h('span', {},
            h('span', { style: styles.tag(CATEGORY_COLORS[cat]) }, cat),
          ),
          h('span', {}, `${summary.categoryBreakdown[cat]} kcal`),
        ),
      ),
    ),

    h('div', { style: styles.section },
      h('div', { style: styles.sectionTitle }, `Meals (${summary.meals.length})`),
      ...summary.meals.map((meal) => {
        const mealCals = meal.items.reduce((s, i) => s + i.calories, 0)
        const time = new Date(meal.timestamp).toLocaleTimeString([], {
          hour: '2-digit',
          minute: '2-digit',
        })

        return h('div', { style: styles.mealCard },
          h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'baseline' } },
            h('span', { style: styles.mealName }, meal.name),
            h('span', { style: styles.mealCalories }, `${mealCals} kcal`),
          ),
          h('div', { style: styles.mealTime }, time),
          h('div', { style: { marginTop: '4px' } },
            ...meal.items.flatMap((item) =>
              item.categories.map((cat) =>
                h('span', { style: styles.tag(CATEGORY_COLORS[cat]) }, cat),
              ),
            ),
          ),
        )
      }),
    ),
  )
}

export const renderWeeklyChart = (days: WeeklyDay[], goal: number) => {
  const maxCal = Math.max(goal, ...days.map((d) => d.totalCalories))
  const chartMax = maxCal > 0 ? maxCal * 1.1 : 2500

  return h('div', { style: styles.container },
    h('div', { style: styles.header }, 'Weekly Calorie Intake'),
    h('div', { style: styles.section },
      ...days.map((day) => {
        const pct = (day.totalCalories / chartMax) * 100
        const goalPct = (goal / chartMax) * 100
        const isOver = day.totalCalories > goal

        return h('div', { style: styles.chartRow },
          h('span', { style: styles.chartLabel }, day.dayLabel),
          h('div', { style: styles.chartBarContainer },
            h('div', { style: styles.chartBar(pct, isOver) }),
            h('div', { style: styles.goalLine(goalPct) }),
          ),
          h('span', { style: styles.chartValue }, `${day.totalCalories}`),
        )
      }),
      h('div', { style: { fontSize: '12px', color: '#FF5722', marginTop: '8px' } },
        `— Goal: ${goal} kcal`,
      ),
    ),
  )
}

export const renderFullView = (summary: DailySummary, weeklyDays: WeeklyDay[]) => {
  return h(Fragment, {},
    renderDailySummary(summary),
    renderWeeklyChart(weeklyDays, summary.goal),
  )
}
